        vector<int> nge(n);
        stack<int> st;
        for (int i = n - 1; i >= 0; --i) {
            while (!st.empty() && st.top() <= arr[i]) st.pop();
            nge[i] = st.empty() ? -1 : st.top();
            st.push(arr[i]);
        }
        for (int i = 0; i < n; ++i) {
            if (i) cout << ' ';
            cout << nge[i];
        }
        cout << '\n';
    }
    return 0;
}

