const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const n = input[idx++];
  const arr = input.slice(idx, idx + n);
  idx += n;
  const nge = new Array(n).fill(-1);
  const stack = [];
  for (let i = n - 1; i >= 0; i--) {
    while (stack.length && stack[stack.length - 1] <= arr[i]) {
      stack.pop();
    }
    nge[i] = stack.length ? stack[stack.length - 1] : -1;
    stack.push(arr[i]);
  }
  outputs.push(nge.join(' '));
}
